import React, { useState } from 'react';
import { Send, Paperclip, Link } from 'lucide-react';
import UserCard from './UserCard';

const GroupDetails = ({ group, onUserClick, onClose }) => {
  const [message, setMessage] = useState('');

  if (!group) return null;

  // Configuração dos status com cores e informações
  const statusConfig = {
    'In meeting': {
      label: 'In a Meeting',
      color: 'bg-blue-500',
      textColor: 'text-blue-400',
      bgColor: 'bg-blue-500/10',
      borderColor: 'border-blue-500/20'
    },
    'Away': {
      label: 'Away',
      color: 'bg-orange-500',
      textColor: 'text-orange-400',
      bgColor: 'bg-orange-500/10',
      borderColor: 'border-orange-500/20'
    },
    'Focus': {
      label: 'Deep Focus',
      color: 'bg-purple-500',
      textColor: 'text-purple-400',
      bgColor: 'bg-purple-500/10',
      borderColor: 'border-purple-500/20'
    },
    'Available': {
      label: 'Available',
      color: 'bg-green-500',
      textColor: 'text-green-400',
      bgColor: 'bg-green-500/10',
      borderColor: 'border-green-500/20'
    },
    'Emergency': {
      label: 'Emergency',
      color: 'bg-red-500',
      textColor: 'text-red-400',
      bgColor: 'bg-red-500/10',
      borderColor: 'border-red-500/20'
    },
    'Out for Lunch': {
      label: 'Logging Out',
      color: 'bg-yellow-500',
      textColor: 'text-yellow-400',
      bgColor: 'bg-yellow-500/10',
      borderColor: 'border-yellow-500/20'
    },
    'Offline': {
      label: 'Offline',
      color: 'bg-gray-500',
      textColor: 'text-gray-400',
      bgColor: 'bg-gray-500/10',
      borderColor: 'border-gray-500/20'
    }
  };

  const config = statusConfig[group.status] || statusConfig['Available'];

  const handleSendNudge = () => {
    if (message.trim()) {
      console.log(`Sending nudge to ${group.status} group: ${message}`);
      setMessage('');
    }
  };

  return (
    <div className="w-80 bg-neutral-900 border-l border-neutral-700 flex flex-col h-full">
      {/* Header */}
      <div className="p-6 border-b border-neutral-700">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-xl font-semibold text-white">Group Details</h2>
          <button
            onClick={onClose}
            className="text-neutral-400 hover:text-white transition-colors"
          >
            ×
          </button>
        </div>

        {/* Status Info */}
        <div className="flex items-center space-x-4">
          <div className={`w-16 h-16 rounded-full ${config.bgColor} ${config.borderColor} border-2 flex items-center justify-center`}>
            <div className={`w-4 h-4 rounded-full ${config.color}`}></div>
          </div>
          <div>
            <h3 className="text-lg font-medium text-white">{config.label}</h3>
            <p className="text-neutral-400">{group.users.length} {group.users.length === 1 ? 'user' : 'users'}</p>
          </div>
        </div>
      </div>

      {/* Quick Nudge */}
      <div className="p-6 border-b border-neutral-700">
        <h3 className="text-lg font-medium text-white mb-4">Quick Nudge</h3>

        {/* Message Input */}
        <div className="space-y-4">
          <div className="relative">
            <textarea
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              placeholder="Type your message..."
              className="w-full bg-neutral-800 border border-neutral-600 rounded-lg px-4 py-3 text-white placeholder-neutral-400 resize-none focus:outline-none focus:border-blue-500 transition-colors"
              rows="3"
            />
          </div>

          {/* Action Buttons */}
          <div className="flex items-center justify-between">
            <div className="flex space-x-2">
              <button className="p-2 text-neutral-400 hover:text-white hover:bg-neutral-700 rounded-lg transition-colors">
                <Paperclip size={20} />
              </button>
              <button className="p-2 text-neutral-400 hover:text-white hover:bg-neutral-700 rounded-lg transition-colors">
                <Link size={20} />
              </button>
            </div>

            <button
              onClick={handleSendNudge}
              disabled={!message.trim()}
              className="bg-blue-600 hover:bg-blue-700 disabled:bg-neutral-700 disabled:text-neutral-400 text-white px-4 py-2 rounded-lg flex items-center space-x-2 transition-colors"
            >
              <Send size={16} />
              <span>Send Nudge</span>
            </button>
          </div>
        </div>
      </div>

      {/* Users List */}
      <div className="flex-1 overflow-y-auto p-6">
        <h3 className="text-lg font-medium text-white mb-4">Group Members</h3>
        <div className="space-y-4">
          {group.users.map((user) => (
            <UserCard
              key={user.id}
              user={user}
              onClick={() => onUserClick(user)}
            />
          ))}
        </div>
      </div>
    </div>
  );
};

export default GroupDetails;
